(function() {
  var SELECTORS = [
    "#onetrust-accept-btn-handler",
    "#CybotCookiebotDialogBodyLevelButtonLevelOptinAllowAll",
    "#CybotCookiebotDialogBodyButtonDecline",
    ".cc-accept",
    ".cc-dismiss",
    "#accept-cookies",
    ".cookie-accept",
    "[data-consent=\"accept\"]",
    "#cookie-accept-btn",
    ".accept-cookies-button",
    ".js-accept-cookies",
    "[aria-label=\"Accept cookies\"]",
    "[aria-label=\"Accept all cookies\"]",
    ".cookie-consent-accept",
    ".cookie-notice__accept",
    "#gdpr-cookie-accept",
    ".gdpr-accept",
    "#cookiescript_accept",
    ".cmplz-accept",
    "#hs-eu-confirmation-button",
    ".fc-cta-consent",
    ".qc-cmp2-summary-buttons button[mode=\"primary\"]",
    "#didomi-notice-agree-button",
    ".sp_choice_type_11",
    "[data-testid=\"cookie-policy-manage-dialog-btn-accept\"]",
    "#consent_prompt_submit",
    ".cn-accept",
    "#ez-accept-all",
    ".cli-plugin-button",
    ".js-cookie-banner-accept",
    ".js-cookie-banner-reject",
    ".govuk-cookie-banner .govuk-button",
    ".cmpboxbtnyes",
    "#cmpwelcomebtnyes a",
    ".cmpboxbtnno",
    "#cmpwelcomebtnno a",
    ".cmpboxbtnsave",
    "#cmpbntyestxt",
    "#cmpbntnotxt",
    ".iubenda-cs-accept-btn",
    "#truste-consent-button",
    ".evidon-banner-acceptbutton",
    "#ensNotifyBanner .accept",
    ".cc-compliance .cc-btn",
    ".cc-nb-okagree",
    ".cc-nb-reject",
    ".cc-cp-foot-accept",
    ".cc-cp-foot-save",
    "[data-cc-event=\"click:dismiss\"]",
    "[data-cc-event=\"click:accept\"]",
    "[aria-label=\"cookieconsent\"] .cc-btn"
  ];

  var TEXT_PATTERNS = /^(accept(\s+(all|analytics))?\s*(cookies)?|reject(\s+(all|analytics))?\s*(cookies)?|agree|allow(\s+all)?|got it|i agree|okay|ok|consent|allow cookies|accept cookies|accept all cookies|dismiss|close|verstanden|akzeptieren|alle akzeptieren|tout accepter|accepter|accepteer alles|aceptar todo|aceptar)$/i;

  function queryAll(root, selector) {
    var results = [];
    try {
      var els = root.querySelectorAll(selector);
      for (var i = 0; i < els.length; i++) results.push(els[i]);
    } catch (e) {}
    return results;
  }

  function getShadowRoots(root) {
    var roots = [];
    var all = root.querySelectorAll('*');
    for (var i = 0; i < all.length; i++) {
      if (all[i].shadowRoot) roots.push(all[i].shadowRoot);
    }
    return roots;
  }

  function queryDeep(selector) {
    var found = document.querySelector(selector);
    if (found) return found;
    var shadows = getShadowRoots(document);
    for (var i = 0; i < shadows.length; i++) {
      found = shadows[i].querySelector(selector);
      if (found) return found;
      var nested = getShadowRoots(shadows[i]);
      for (var j = 0; j < nested.length; j++) {
        found = nested[j].querySelector(selector);
        if (found) return found;
      }
    }
    return null;
  }

  function queryAllDeep(selector) {
    var results = queryAll(document, selector);
    var shadows = getShadowRoots(document);
    for (var i = 0; i < shadows.length; i++) {
      results = results.concat(queryAll(shadows[i], selector));
      var nested = getShadowRoots(shadows[i]);
      for (var j = 0; j < nested.length; j++) {
        results = results.concat(queryAll(nested[j], selector));
      }
    }
    return results;
  }

  function isVisible(el) {
    if (!(el instanceof HTMLElement)) return false;
    if (el.offsetParent !== null) return true;
    var style = getComputedStyle(el);
    return style.display !== 'none' && style.visibility !== 'hidden' && style.opacity !== '0';
  }

  function clickBySelectorMatch() {
    for (var i = 0; i < SELECTORS.length; i++) {
      var el = queryDeep(SELECTORS[i]);
      if (el && isVisible(el)) {
        el.click();
        return true;
      }
    }
    return false;
  }

  function clickByTextMatch() {
    var selectors = 'button, a[role=\"button\"], [role=\"button\"], [class*=\"cookie\"] button, [class*=\"consent\"] button, [id*=\"cookie\"] button, [id*=\"consent\"] button, [class*=\"banner\"] button, [class*=\"gdpr\"] button, [class*=\"cmp\"] a[role=\"button\"]';
    var candidates = queryAllDeep(selectors);
    for (var i = 0; i < candidates.length; i++) {
      var el = candidates[i];
      if (isVisible(el)) {
        var text = (el.textContent || '').trim();
        if (TEXT_PATTERNS.test(text)) {
          el.click();
          return true;
        }
      }
    }
    return false;
  }

  function dismiss() {
    return clickBySelectorMatch() || clickByTextMatch();
  }

  if (dismiss()) return;

  var observer = new MutationObserver(function() {
    if (dismiss()) {
      observer.disconnect();
    }
  });
  observer.observe(document.body, { childList: true, subtree: true });
  setTimeout(function() { observer.disconnect(); }, 10000);
})();
